sheet.script:
(function () {
    window.avicolaDashboardInlineLoaded = true;
    console.log('Dashboard inline script running');
    function loadChartJs(callback) {
        console.log('Dashboard loadChartJs start');
        if (window.Chart) { console.log('Chart.js already loaded'); callback(); return; }
        var script = document.createElement('script');
        script.src = 'https://cdn.jsdelivr.net/npm/chart.js@3.9.1/dist/chart.min.js';
        script.onload = function () {
            console.log('Chart.js loaded');
            callback();
        };
        script.onerror = function () {
            console.error('No se pudo cargar Chart.js desde CDN.');
        };
        document.head.appendChild(script);
    }

    function rpcCall(model, method, args, kwargs) {
        var url = '/web/dataset/call_kw';
        console.log('Dashboard RPC url:', url, 'model:', model, 'method:', method, 'args:', args);
        var csrf = null;
        try {
            var meta = document.querySelector('meta[name="csrf-token"]');
            if (meta) { csrf = meta.getAttribute('content'); }
        } catch (e) { csrf = null; }
        return fetch(url, {
            method: 'POST',
            credentials: 'same-origin',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json; charset=utf-8',
                'X-Requested-With': 'XMLHttpRequest',
                'X-CSRFToken': csrf || (window.csrf_token || '')
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: {
                    model: model,
                    method: method,
                    args: args,
                    kwargs: kwargs || {}
                }
            })
        }).then(function (response) {
            if (!response.ok) {
                return response.text().then(function (t) {
                    throw new Error('HTTP ' + response.status + ' ' + response.statusText + ': ' + t);
                });
            }
            return response.json();
        }).then(function (json) {
            if (json.error) {
                var msg = (json.error && json.error.data && json.error.data.message) || (json.error.message) || 'RPC error';
                throw new Error(msg);
            }
            return json.result;
        });
    }

    function showChartError(message) {
        window.avicolaDashboardInlineLoaded = true;
        var ids = ['chart_galpones', 'chart_densidades', 'chart_pie'];
        ids.forEach(function (chartId) {
            var ctx = document.getElementById(chartId);
            if (!ctx || !ctx.parentElement) {
                return;
            }
            var existing = ctx.parentElement.querySelector('.dashboard-error');
            if (existing) {
                existing.textContent = message;
                return;
            }
            var errorTag = document.createElement('div');
            errorTag.className = 'dashboard-error';
            errorTag.style.color = '#ff6b6b';
            errorTag.style.padding = '10px 0 0';
            errorTag.style.fontSize = '0.95rem';
            errorTag.textContent = message;
            ctx.parentElement.appendChild(errorTag);
        });
    }

    function renderOverviewCharts() {
        var domain = [];
        if (availableGranjaIds.length) {
            domain = [['granja_id', 'in', availableGranjaIds]];
        }
        rpcCall('avicola.galpon', 'search_read', [domain, ['cantidad_actual', 'metros_cuadrados', 'granja_id']])
            .then(function (data) {
                var farms = {};
                data.forEach(function (row) {
                    var farm = (row.granja_id && row.granja_id[1]) || 'Sin Granja';
                    if (!farms[farm]) {
                        farms[farm] = { aves: 0, metros: 0 };
                    }
                    farms[farm].aves += row.cantidad_actual || 0;
                    farms[farm].metros += row.metros_cuadrados || 0;
                });

                var labels = Object.keys(farms);
                var aves = labels.map(function (farm) { return farms[farm].aves; });
                var densities = labels.map(function (farm) {
                    return farms[farm].metros > 0
                        ? farms[farm].aves / farms[farm].metros
                        : 0;
                });
                var palette = ['#722f77', '#5c2261', '#e9b3f0', '#dcb3e3', '#bca0bf'];

                if (chartDensidades) { chartDensidades.destroy(); }
                if (chartPie) { chartPie.destroy(); }

                var ctxB = document.getElementById('chart_densidades');
                if (ctxB) {
                    chartDensidades = new Chart(ctxB.getContext('2d'), {
                        type: 'line',
                        data: {
                            labels: labels,
                            datasets: [{
                                label: 'Densidad por Granja',
                                data: densities,
                                borderColor: '#e9b3f0',
                                backgroundColor: 'rgba(233,179,240,0.2)',
                                tension: 0.3
                            }]
                        },
                        options: { responsive: true, maintainAspectRatio: false }
                    });
                }

                var ctxC = document.getElementById('chart_pie');
                if (ctxC) {
                    chartPie = new Chart(ctxC.getContext('2d'), {
                        type: 'bar',
                        data: {
                            labels: labels,
                            datasets: [{
                                label: 'Aves por Granja',
                                data: aves,
                                backgroundColor: labels.map(function (_, i) {
                                    return palette[i % palette.length];
                                })
                            }]
                        },
                        options: { responsive: true, maintainAspectRatio: false }
                    });
                }
            }).catch(function (err) {
                console.error('Error RPC al obtener galpones', err);
                showChartError('Error cargando datos: ' + (err.message || err));
            });
    }

    var chartGalpones = null;
    var chartDensidades = null;
    var chartPie = null;
    var selectedGranjaId = null;
    var selectedMortGranjaId = null;
    var availableGranjaIds = [];
    var chartGranjaSelect = null;
    var mortGranjaSelect = null;

    function updateChartObjects(newGalpones, newDensidades, newLabels) {
        if (chartGalpones) { chartGalpones.destroy(); }
        if (chartDensidades) { chartDensidades.destroy(); }
        if (chartPie) { chartPie.destroy(); }

        var ctxA = document.getElementById('chart_galpones');
        var ctxB = document.getElementById('chart_densidades');
        var ctxC = document.getElementById('chart_pie');
        var palette = ['#722f77', '#5c2261', '#e9b3f0', '#dcb3e3', '#bca0bf'];

        if (ctxA) {
            chartGalpones = new Chart(ctxA.getContext('2d'), {
                type: 'bar',
                data: {
                    labels: newLabels,
                    datasets: [{
                        label: 'Aves por Galpón',
                        data: newGalpones,
                        backgroundColor: '#722f77'
                    }]
                },
                options: { responsive: true, maintainAspectRatio: false }
            });
        }
        if (ctxB) {
            chartDensidades = new Chart(ctxB.getContext('2d'), {
                type: 'line',
                data: {
                    labels: newLabels,
                    datasets: [{
                        label: 'Densidad (aves/m²)',
                        data: newDensidades,
                        borderColor: '#e9b3f0',
                        backgroundColor: 'rgba(233,179,240,0.15)',
                        tension: 0.3
                    }]
                },
                options: { responsive: true, maintainAspectRatio: false }
            });
        }
        if (ctxC) {
            chartPie = new Chart(ctxC.getContext('2d'), {
                type: 'pie',
                data: {
                    labels: newLabels,
                    datasets: [{
                        data: newGalpones,
                        backgroundColor: newLabels.map(function (_, i) {
                            return palette[i % palette.length];
                        })
                    }]
                },
                options: { responsive: true, maintainAspectRatio: false }
            });
        }
    }

    function refreshCharts() {
        var domain = [];
        if (selectedGranjaId) {
            domain = [['granja_id', '=', parseInt(selectedGranjaId, 10)]];
        }
        rpcCall('avicola.galpon', 'search_read', [domain, ['name', 'cantidad_actual', 'metros_cuadrados']])
            .then(function (data) {
                var labels = data.map(function (d) { return d.name || 'Sin Nombre'; });
                var counts = data.map(function (d) { return d.cantidad_actual || 0; });
                if (chartGalpones) { chartGalpones.destroy(); }
                var ctxA = document.getElementById('chart_galpones');
                if (ctxA) {
                    chartGalpones = new Chart(ctxA.getContext('2d'), {
                        type: 'bar',
                        data: {
                            labels: labels,
                            datasets: [{
                                label: 'Aves por Galpón',
                                data: counts,
                                backgroundColor: '#722f77'
                            }]
                        },
                        options: { responsive: true, maintainAspectRatio: false }
                    });
                }
            }).catch(function (err) {
                console.error('Error RPC al obtener galpones', err);
                showChartError('Error cargando datos: ' + (err.message || err));
            });
    }

    function refreshMortality() {
        try {
            var targetEl = document.getElementById('avicola-mortalidad-percent');
                                    if (!targetEl) { return; }
                                    if (!selectedMortGranjaId) {
                                        targetEl.textContent = '—';
                                        return;
                                    }
                                    rpcCall('avicola.dashboard', 'get_mortalidad_percentage', [parseInt(selectedMortGranjaId, 10)])
                .then(function (percent) {
                    var pct = (typeof percent === 'number') ? percent : parseFloat(percent) || 0;
                    targetEl.textContent = pct.toFixed(1) + '%';
                }).catch(function (err) {
                    console.error('Error RPC al obtener mortalidad', err);
                    if (targetEl) { targetEl.textContent = 'Error'; }
                });
        } catch (e) {
            console.error('refreshMortality error', e);
        }
    }

    function refreshCards() {
        rpcCall('avicola.dashboard', 'get_metrics', [], {})
            .then(function (metrics) {
                try {
                    var set = function (id, value, fmt) {
                        var el = document.getElementById(id);
                        if (!el) { return; }
                        if (fmt === 'int') { el.textContent = parseInt(value, 10) || 0; }
                        else if (fmt === 'float') { el.textContent = (parseFloat(value) || 0).toFixed(2); }
                        else { el.textContent = value != null ? value : '—'; }
                    };
                    set('avicola-total-granjas', metrics.total_granjas, 'int');
                    set('avicola-total-galpones', metrics.total_galpones, 'int');
                    set('avicola-total-aves', metrics.total_aves, 'int');
                    set('avicola-total-veterinarios', metrics.total_veterinarios, 'int');
                    set('avicola-total-ingresos', metrics.total_ingresos_pollitos, 'int');
                    set('avicola-total-salidas', metrics.total_salidas_matadero, 'int');
                    set('avicola-total-peso', metrics.peso_total_despachado, 'float');
                } catch (e) {
                    console.error('refreshCards error', e);
                }
            }).catch(function (err) {
                console.error('Error RPC al obtener métricas', err);
            });
    }

    function loadGranjas() {
        rpcCall('avicola.dashboard', 'get_available_granjas', [], {})
            .then(function (granjas) {
                availableGranjaIds = granjas.map(function (granja) { return granja.id; });
                chartGranjaSelect = document.getElementById('avicola-granja-chart-select');
                mortGranjaSelect = document.getElementById('avicola-granja-select');

                if (chartGranjaSelect) {
                    chartGranjaSelect.innerHTML = '<option value="">Selecciona una granja...</option>';
                }
                if (mortGranjaSelect) {
                    mortGranjaSelect.innerHTML = '<option value="">Selecciona una granja...</option>';
                }

                granjas.forEach(function (granja) {
                    var opt1 = document.createElement('option');
                    opt1.value = granja.id;
                    opt1.textContent = granja.name;
                    if (chartGranjaSelect) { chartGranjaSelect.appendChild(opt1.cloneNode(true)); }

                    var opt2 = document.createElement('option');
                    opt2.value = granja.id;
                    opt2.textContent = granja.name;
                    if (mortGranjaSelect) { mortGranjaSelect.appendChild(opt2); }
                });

                if (granjas.length === 1) {
                    selectedGranjaId = granjas[0].id;
                    selectedMortGranjaId = granjas[0].id;
                    if (chartGranjaSelect) { chartGranjaSelect.value = selectedGranjaId; }
                    if (mortGranjaSelect) { mortGranjaSelect.value = selectedMortGranjaId; }
                }

                if (chartGranjaSelect) {
                    chartGranjaSelect.addEventListener('change', function () {
                        selectedGranjaId = this.value;
                        refreshCharts();
                    });
                }
                if (mortGranjaSelect) {
                    mortGranjaSelect.addEventListener('change', function () {
                        selectedMortGranjaId = this.value;
                        refreshMortality();
                    });
                }

                renderOverviewCharts();
                refreshCharts();
                refreshMortality();
                refreshCards();
            }).catch(function (err) {
                console.error('Error RPC al obtener granjas', err);
                showChartError('Error cargando granjas: ' + (err.message || err));
            });
    }

    loadChartJs(loadGranjas);
})();
